import React, { useState } from "react";
import DashboardHeader from "../components/DashboardHeader";
import KPICards from "../components/KPICards";
import GrowthChart from "../components/GrowthChart";
import CostDonutChart from "../components/CostDonutChart";
import CourseList from "../components/CourseList";
import StudentTeacherChart from "../components/StudentTeacherChart";
import PhucAnSidebar from "../components/PhucAnSidebar";

const ChartsDashboard = () => {
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);

  return (
    <div style={{ display: "flex", minHeight: "100vh", background: "#F5F6F8" }}>
      {/* Sidebar */}
      <PhucAnSidebar collapsed={sidebarCollapsed} onToggle={setSidebarCollapsed} />

      {/* Main Content */}
      <div
        style={{
          flex: 1,
          marginLeft: sidebarCollapsed ? 72 : 240,
          transition: "margin-left 0.2s ease",
          padding: "24px 28px",
          minWidth: 0,
        }}
      >
        <DashboardHeader />
        <KPICards />
        <GrowthChart />
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit, minmax(360px, 1fr))",
            gap: 20,
            marginTop: 0,
          }}
        >
          <CostDonutChart />
          <CourseList />
        </div>
        <StudentTeacherChart />
      </div>
    </div>
  );
};

export default ChartsDashboard;

:root {
  font-family: system-ui, Avenir, Helvetica, Arial, sans-serif;
  line-height: 1.5;
  font-weight: 400;

  color-scheme: light dark;
  color: rgba(255, 255, 255, 0.87);
  background-color: #242424;

  font-synthesis: none;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* custom.css */
.side-nav-title {
  margin-top: 20px;
  margin-left: -10px;
  font-size: 0.9rem !important;
  line-height: 0.1;
}

.ant-select-selector {
  height: 38px !important;
  border-radius: 0.375rem;
