  color: #fff !important;
  border: 1px solid #f1b53d !important;
}

.btn-result-table {
  background-color: #3db9dc;
  color: #fff;
}

.btn-result-table:hover {
  background-color: #3db9dc !important;
  color: #fff !important;
  opacity: 0.7;
  border: 1px solid #3db9dc !important;
}

.btn-delete-table {
  background-color: #ff5d48 !important;
  color: #fff !important;
}

