  gap: 4px;
  padding: 8px 8px;
  border: 1px solid #efefef;
  border-radius: 5px;
}

.time-separator {
  padding: 0 4px;
  color: rgba(0, 0, 0, 0.65);
}

.import-products .ant-upload-select {
  height: unset !important;
}
.import-products .ant-upload-list-item-container {
  height: unset !important;
}

.import-products .ant-upload-list-text {
  margin-top: -6px !important;
