.rotate-90 {
  transform: rotate(90deg);
}
.sub-menu {
  padding-left: 40px;
  transition: all 0.25s ease;
}

.link-side-nav-btn {
  padding: 16px 67px 16px 40px !important;
}

.link-side-nav-btn .menu-icon {
  margin-right: 0 !important;
}

.btn-side-nav {
  padding: 14px 4px 20px;
}

.container-menu {
  width: 160px;
  display: flex;
  align-items: center;
}

.btn-side-nav {
